// Lấy data từ node trước (Edit Fields3)
const input = $input.first().json;

// 1. Lấy các thông tin đầu vào
const evaluatorListRaw = input.evaluator_list || [];
const rows = input.rows || [];
const evaluatorColumnId = input.evaluator_col_id;

// --- MỚI THÊM: Lấy ID cột Date và Giá trị Date ---
// Sửa lỗi khoảng trắng ở key 'assigned_date_col_id '
const assignedDateColumnId = input['assigned_date_col_id'] || input['assigned_date_col_id '];

const dateToSet = $now.toFormat('yyyy-MM-dd');
// ------------------------------------------------

// Cấu hình cụm phân bổ
const BATCH_SIZE = 20;

// Map platform -> index (giữ nguyên logic cũ của bạn)
const platformColumnIndexMap = {
  ios: 4,
  android: 6,
};

function rowSupportPlatform(row, platform) {
  if (!platform || platform === 'all') return true;
  const idx = platformColumnIndexMap[platform];
  if (idx == null) return false;
  const cell = row.cells[idx];
  const value = cell?.displayValue ?? cell?.value ?? "";
  return value !== "";
}

// --- LOGIC CHIA QUOTA (GIỮ NGUYÊN) ---
const evaluators = evaluatorListRaw.map((ev, index) => ({
  name: ev.name,
  platform: (ev.platform || 'all').toLowerCase(),
  index,
  quota: 0,
  assigned: 0,
}));

const totalGames = rows.length;
const totalEvals = evaluators.length || 1;
const baseQuota = Math.floor(totalGames / totalEvals);
let extra = totalGames % totalEvals;

for (const ev of evaluators) {
  ev.quota = baseQuota + (extra > 0 ? 1 : 0);
  if (extra > 0) extra--;
}

const specificEvals = evaluators.filter(ev => ev.platform !== 'all');
const allEvals = evaluators.filter(ev => ev.platform === 'all');
const orderedEvals = [...specificEvals, ...allEvals];

// --- LOGIC PHÂN BỔ XOAY VÒNG THEO CỤM (CẬP NHẬT) ---
const assignment = new Map();
let remainingRows = [...rows];

// Lặp cho đến khi hết hàng hoặc không ai có thể nhận thêm việc
let appsAssignedInLastLoop = true;
while (remainingRows.length > 0 && appsAssignedInLastLoop) {
  appsAssignedInLastLoop = false;

  for (const ev of orderedEvals) {
    let need = ev.quota - ev.assigned;
    if (need <= 0) continue;

    // Mỗi lượt lấy tối đa 20 game hoặc số lượng cần thiết còn lại
    let currentBatchSize = Math.min(need, BATCH_SIZE);

    // Lọc hàng phù hợp platform cho người này
    const compatibleRows = remainingRows.filter(row =>
      rowSupportPlatform(row, ev.platform)
    );

    if (compatibleRows.length > 0) {
      const toAssign = compatibleRows.slice(0, currentBatchSize);

      for (const row of toAssign) {
        assignment.set(row.id, ev.name);
        ev.assigned++;

        // Xóa hàng đã giao khỏi danh sách chờ ngay lập tức
        const rowIndex = remainingRows.findIndex(r => r.id === row.id);
        if (rowIndex > -1) remainingRows.splice(rowIndex, 1);
      }
      appsAssignedInLastLoop = true;
    }
  }
}

// --- LOGIC TẠO PAYLOAD UPDATE (CẬP NHẬT) ---
const rowsToUpdate = rows
  .filter(row => assignment.has(row.id))
  .map(row => ({
    id: row.id,
    cells: [
      // Update cột Người được assign
      {
        columnId: evaluatorColumnId,
        value: assignment.get(row.id),
      },
      // --- MỚI THÊM: Update cột Ngày assign ---
      {
        columnId: assignedDateColumnId,
        value: dateToSet,
      }
    ],
  }));

return [
  {
    json: {
      rows: rowsToUpdate,
    },
  },
];

// 1. Lấy dữ liệu CỘT (từ node "Get Columns")
// Lưu ý: Thay đổi tên trong $() nếu tên node của bạn khác
const columnsList = $('Get Columns').first().json.data

// 2. Tìm ID và Index của 2 cột cần thiết dựa theo TÊN (Title)
// Bạn không cần quan tâm nó nằm ở vị trí nào nữa
const evalCol = columnsList.find(c => c.title === "Initial Evaluator");
const createdCol = columnsList.find(c => c.title === "Release Date");

const assignedCol = columnsList.find(c => c.title === "Assigned Date");

// Kiểm tra xem có tìm thấy cột không (đề phòng sai tên)
if (!evalCol || !createdCol) {
  throw new Error("Không tìm thấy cột 'Initial Evaluator' hoặc 'Created'. Hãy kiểm tra lại tên cột trong Sheet.");
}

// 3. Lấy dữ liệu DÒNG (từ node "Get Modified Rows...")
const sheetData = $('Get Modified Rows since last 3 days').first().json;
const rows = sheetData.rows || [];

// 4. Thực hiện lọc (Filter)
const filteredRows = rows.filter((row) => {
  // Lấy ô dữ liệu dựa vào Index của cột đã tìm được ở trên
  // (Dùng index nhanh và chính xác hơn find trong mảng cells)
  const evalCell = row.cells[evalCol.index];
  const createdCell = row.cells[createdCol.index];

  // Hàm lấy giá trị an toàn
  const getVal = (cell) => cell?.displayValue ?? cell?.value ?? "";

  const evalValue = getVal(evalCell);
  const createdValue = getVal(createdCell);

  // ĐIỀU KIỆN LỌC:
  // 1. Initial Evaluator phải TRỐNG (=== "")
  // 2. VÀ (&&) Created phải CÓ DỮ LIỆU (!== "")
  return evalValue === "" && createdValue !== "";
});

// 5. Trả về kết quả
return [
  {
    json: {
      evaluatorColumnId: evalCol.id, // ID để dùng cho việc update sau này
      assignedColumnId: assignedCol,
      rows: filteredRows,
    },
  },
];

