const input = $input.first().json;

// input từ Edit Fields
const evaluatorColumnId = input.evaluator_col_id;
const rows = input.rows || [];
const evaluatorListRaw = input.evaluator_list || [];

if (!evaluatorColumnId) throw new Error("Missing evaluator_col_id");
if (!Array.isArray(rows)) throw new Error("rows must be an array");
if (!Array.isArray(evaluatorListRaw)) throw new Error("evaluator_list must be an array");

// evaluator_list: [{name, platform?}, ...]
const evaluators = evaluatorListRaw
  .map((ev) => ({
    name: (ev?.name ?? "").toString().trim(),
    platform: (ev?.platform ?? "all").toString().toLowerCase(),
  }))
  .filter((ev) => ev.name);

if (evaluators.length === 0) throw new Error("evaluator_list empty");

// --- (giữ logic platform index như code gốc nếu bạn cần) ---
const platformColumnIndexMap = { ios: 4, android: 6 };

function rowSupportPlatform(row, platform) {
  if (!platform || platform === "all") return true;
  const idx = platformColumnIndexMap[platform];
  if (idx == null) return false;
  const cell = row.cells?.[idx];
  const value = cell?.displayValue ?? cell?.value ?? "";
  return String(value).trim() !== "";
}

// --- chia quota y như code gốc ---
const totalGames = rows.length;
const totalEvals = evaluators.length || 1;
const baseQuota = Math.floor(totalGames / totalEvals);
let extra = totalGames % totalEvals;

const evalsWithQuota = evaluators.map((ev) => ({
  ...ev,
  quota: baseQuota + (extra-- > 0 ? 1 : 0),
  assigned: 0,
}));

const specificEvals = evalsWithQuota.filter((ev) => ev.platform !== "all");
const allEvals = evalsWithQuota.filter((ev) => ev.platform === "all");
const orderedEvals = [...specificEvals, ...allEvals];

const assignment = new Map();
let remainingRows = [...rows];

for (const ev of orderedEvals) {
  let need = ev.quota - ev.assigned;
  if (need <= 0 || remainingRows.length === 0) continue;

  const compatibleRows = remainingRows.filter((row) =>
    rowSupportPlatform(row, ev.platform)
  );

  const toAssign = compatibleRows.slice(0, need);

  for (const row of toAssign) {
    assignment.set(row.id, ev.name);
    ev.assigned++;
  }

  remainingRows = remainingRows.filter((row) => !assignment.has(row.id));
}

// --- tạo rowsToUpdate đúng schema Smartsheet ---
const rowsToUpdate = rows
  .filter((row) => assignment.has(row.id))
  .map((row) => ({
    id: row.id,
    cells: [
      {
        columnId: evaluatorColumnId,
        value: assignment.get(row.id),
      },
    ],
  }));

// ✅ RETURN: để truyền thẳng vào Smartsheet update node
return [
  {
    json: {
      rows: rowsToUpdate,
    },
  },
];

// 1. Lấy dữ liệu CỘT
const columnsList = $('Get Columns1').first().json.data;

