const assignedCol = columnsList.find(c => c.title === "Assigned Date");

const evaluatorCol = columnsList.find(c => c.title === "Evaluator");

if (!assignedCol) {
  throw new Error("Không tìm thấy cột 'Assigned Date'. Hãy kiểm tra lại tên cột trong Sheet.");
}

if (!evaluatorCol) {
  throw new Error("Không tìm thấy cột 'Evaluator'. Hãy kiểm tra lại tên cột trong Sheet.");
}


// 3. Lấy dữ liệu DÒNG
const sheetData = $('Get Modified Rows since last 3 days1').first().json;
const rows = sheetData.rows || [];

// 4. Lọc: Assigned Date CÓ dữ liệu + Evaluator TRỐNG
const filteredRows = rows.filter((row) => {
  const assignedCell = row.cells?.[assignedCol.index];
  const evaluatorCell = row.cells?.[evaluatorCol.index];

  // Hàm lấy giá trị an toàn
  const getVal = (cell) => cell?.displayValue ?? cell?.value ?? "";

  const assignedValue = String(getVal(assignedCell)).trim();
  const evaluatorValue = String(getVal(evaluatorCell)).trim();

  // Điều kiện:
  // - Assigned Date có dữ liệu
  // - Evaluator trống
  return assignedValue !== "" && evaluatorValue === "";
});


